import React, {
    forwardRef,
    useCallback,
    useEffect,
    useImperativeHandle,
    useRef,
    useState,
} from "react";
import type { IKitsInputTextarea } from "@lmb/kitsconcerto-types";
import KitsContainer from "../../Helpers/FormContainer";
import { useSeparator } from "../../../../../Factory";
import { applyKeyFilter } from "../InputText/keyFilter.native";

// ✅ correct Gluestack components
import {
    Textarea,
    TextareaInput,
} from "@lmb/kitsconcertomobile";
import {useComponentDefaults} from "@lmb/kitsconcerto/Hooks";

type NativeTextareaRef = {
    focus(): void;
    blur(): void;
    clear(): void;
};

const KitsInputTextarea = forwardRef<
    NativeTextareaRef,
    IKitsInputTextarea
>((rawProps, ref) => {
    const {mergedProps: props, themeStyle} = useComponentDefaults('Textarea', rawProps);
    const {
        id,
        label,
        value,
        defaultValue,
        onChange,
        keyFilter,
        errors,
        hideError,
        invalid,
        isFloatedLabel,
        disabled,
        helperText,
        inputSize,
        containerStyle,
        localProps,
        ...rest
    } = props;

    const isControlled = value !== undefined;

    const { cssProps, nativeProps } = useSeparator<any>({
        ...(rest as any),
        ...(localProps as any),
    });

    const fieldRef = useRef<any>(null);

    /** internal state for uncontrolled mode */
    const [internalValue, setInternalValue] = useState<string>(
        () => String(defaultValue ?? "")
    );

    /** sync when controlled */
    useEffect(() => {
        if (isControlled) {
            setInternalValue(String(value ?? ""));
        }
    }, [isControlled, value]);

    useImperativeHandle(ref, () => ({
        focus: () => fieldRef.current?.focus?.(),
        blur: () => fieldRef.current?.blur?.(),
        clear: () => {
            if (!isControlled) setInternalValue("");
            onChange?.({ target: { value: "" } } as any);
        },
    }));

    const handleChangeText = useCallback(
        (nextRaw: string) => {
            const prev = isControlled
                ? String(value ?? "")
                : internalValue;

            const filtered = keyFilter
                ? applyKeyFilter(prev, nextRaw, keyFilter as any)
                : nextRaw;

            if (!isControlled) {
                setInternalValue(filtered);
            }

            // Prime-like event
            onChange?.({ target: { value: filtered } } as any);
        },
        [keyFilter, onChange, isControlled, internalValue, value],
    );

    const displayValue = isControlled
        ? String(value ?? "")
        : internalValue;

    return (
        <KitsContainer
            id={id}
            helperText={helperText}
            isFloatedLabel={isFloatedLabel}
            errors={errors}
            invalid={invalid}
            label={label}
            hideError={hideError}
            disabled={disabled}
            inputSize={inputSize}
            containerStyle={containerStyle}
        >
            <Textarea
                size={inputSize ?? "md"}
                isDisabled={!!disabled}
                isInvalid={!!invalid}
                style={{...(themeStyle as any), ...(cssProps as any)}}
                {...nativeProps}
            >
                <TextareaInput
                    ref={fieldRef}
                    value={displayValue}
                    onChangeText={handleChangeText}
                    editable={!disabled}
                />
            </Textarea>
        </KitsContainer>
    );
});

KitsInputTextarea.displayName = "KitsInputTextarea";
export default KitsInputTextarea;
